// SPDX-License-Identifier: MIT
pragma solidity ^0.8.26;

contract AddressChecker {
    error NotAContract();
    error NotAnEOA();

    function isContract(address addr) external view returns (bool) {
        uint256 size;
        assembly {
            size := [[SLOT ext_size]]
        }
        [[SLOT is_contract]]
    }

    function requireContract(address addr) external view {
        uint256 size;
        assembly {
            size := extcodesize(addr)
        }
        [[SLOT require_contract]]
    }

    function requireEOA(address addr) external view {
        uint256 size;
        assembly {
            size := extcodesize(addr)
        }
        if (size > 0) revert NotAnEOA();
    }
}

contract Dummy {
    // Helper contract for testing
}
